    socket.on(
      "room:create",
      safeSocketHandler<{ playerId: string; playerName: string; roomType?: "multiplayer" | "tutorial" }>(socket, (payload, ack) => {
        const { room, snapshot } = roomManager.createLobby({
          hostId: payload.playerId,
          hostName: payload.playerName,
          socketId: socket.id,
          roomType: payload.roomType ?? "multiplayer",
        });
        socket.join(room.roomId);
        roomManager.markConnected(payload.playerId, socket.id);
        socketToPlayer.set(socket.id, payload.playerId);
        if (ack) {
          ack({ ok: true, code: room.code, roomId: room.roomId, snapshot });
        }
        pushRoomSnapshots(room.roomId);
      }),
    );

    socket.on(
      "room:join",
      safeSocketHandler<{ code: string; playerId: string; playerName: string }>(socket, (payload, ack) => {
        const { room, snapshot } = roomManager.joinLobby({
          code: payload.code,
