async function emitAck<T = unknown>(socket: Socket, event: string, payload: unknown): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    socket.timeout(2000).emit(event, payload, (err: Error | null, response: T) => {
      if (err) {
        reject(err);
        return;
      }
      resolve(response);
    });
  });
}

async function waitForSocketEvent<T = unknown>(socket: Socket, event: string, timeoutMs = 3000): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    const timer = setTimeout(() => {
      socket.off(event, onEvent);
      reject(new Error(`Timeout waiting for socket event: ${event}`));
    }, timeoutMs);

    const onEvent = (payload: T) => {
      clearTimeout(timer);
      socket.off(event, onEvent);
      resolve(payload);
    };

    socket.on(event, onEvent);
  });
}

async function waitForStep(stepQueue: string[], target: string, timeoutMs = 4000): Promise<void> {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    if (stepQueue.includes(target)) {
      return;
    }
    await new Promise((resolve) => setTimeout(resolve, 15));
  }
  throw new Error(`Timeout waiting tutorial step ${target}`);
}

async function waitForCompleted(queue: Array<{ roomId: string; userId: string }>, timeoutMs = 3000): Promise<{ roomId: string; userId: string }> {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    const found = queue.find((item) => item.userId.length > 0);
    if (found) {
      return found;
    }
    await new Promise((resolve) => setTimeout(resolve, 15));
  }
  throw new Error("Timeout waiting for tutorial completion queue");
}

